/** SummUpgBonus(b) — "SummUpgBonus"==d, N.js byte 10665909, VERBATIM:
 *   SumUpgMoltoz = 1
 *   if Holes[28].includes(b):                                  // The Hole's "CavernsOwned"-like flag list
 *     SumUpgMoltoz = 2 + (max(0, getbonus2(1,597,-1)/100 - 1) + SummUpgBonus(78)/100)   // recursive!
 *   if SumStoneTrialz(SummonUPG[b][2], 0) > 0 && SummonUPG[b][10] == 1:                  // stoneTrialFlag gate
 *     SumUpgMoltoz *= (1 + SumStoneTrialz(SummonUPG[b][2], 0))    // colour field IS the stone index arg
 *   return SumUpgMoltoz * Summon[0][b] * SummonUPG[b][6]          // level * bonusQty, times the above multi
 *
 * SumStoneTrialz(colour,0) = KRbest["SummzTrz"+colour] (kills on that colour's summoning stone) — see
 * SUMMONING_STONES below. The Holes[28] branch (a rare "doubled" flag list, separate from The Hole's
 * CavernsOwned) and the `getbonus2(1,597,-1)` talent term are transcribed as-is; talent id 597 and the
 * exact membership of Holes[28] were not traced further in this pass (out of scope: not a summoning-
 * owned table).
 */
export function summUpgBonus(level, bonusQty, stoneTrialMulti = 0) {
  // Simplified pure form for the COMMON case (not in Holes[28], no stone-trial stacking):
  //   SummUpgBonus(b) = level * bonusQty
  // Pass stoneTrialMulti = SumStoneTrialz(colour,0) when SummonUPG[b][10]==1 to include stone-trial stacking:
  //   SummUpgBonus(b) = (1 + stoneTrialMulti) * level * bonusQty
  return (1 + Math.max(0, stoneTrialMulti)) * level * bonusQty;
}

/** UpgCost(b) — "UpgCost"==d, N.js byte 10667117, VERBATIM (Summon[0][b] = current level):
 *   1 / (1 + getbonus2(1,595,-1) * max(0, floor(CalcTalentMAP[595]/100)) / 100)   // class talent id 595
 *   * 1 / (1 + SummUpgBonus(49)/100)                                              // "Cost Crashing" (id 49)
 *   * max(.1, 1 - max(RoG_BonusQTY(9,0), RoG_BonusQTY(34,0))/100)                 // sushi (RoG ids 9,34 ONLY)
 *   * 1 / (1 + ArcaneUpgBonus(54,0) * OptLacc[319] / 100)                        // tesseract x highest endless lv
 *   * 1 / (1 + SummUpgBonus(57)/100)                                              // "Cost Deflation" (id 57)
 *   * 1 / (1 + SummUpgBonus(72)/100)                                              // "Sell Sell Sell" (id 72)
 *   * 1 / (1 + SummUpgBonus(75) * max(0, GenINFO[170]) / 100)                     // "Cost Laundering" (id 75)
 *   * SummonUPG[b][4]                                                             // base cost
 *   * Math.pow(SummonUPG[b][5], Summon[0][b])                                     // costExponent ^ level
 *
 * GenINFO[170] IS floor(totalUpgradeLevels/100) — confirmed by its own assignment site (N.js byte
 * 11373136 and 3 siblings: `this._GenINFO[170]=Math.floor(this._DN5/100)` where
 * `this._DN5 = sum(Summon[0])` i.e. the exact sum-of-all-levels, recomputed/cached whenever an
 * upgrade changes — NOT a transient per-battle-only counter, so it IS save-derivable as
 * floor(totalUpgradeLevels/100) with no caveat.
 *
 * DIVERGENCE FROM idleon-toolbox (summoning.ts:132-143's `upgrades.map(...)` cost calc): toolbox's
 * cost formula is MISSING three real N.js terms entirely — the talent-595 term, SummUpgBonus(72)
 * ("Sell Sell Sell"), and SummUpgBonus(75) ("Cost Laundering") — and it ADDS an extra sushi
 * reduction pair (RoG ids 38,47) that does NOT appear in THIS dispatcher case at all (ids 38/47
 * belong to na.UpgradeVault's SEPARATE "VaultUpgCost" case, byte 10634213 — toolbox's summoning.ts
 * conflates the two systems' sushi discounts). The ids toolbox DOES have right: costDeflation=49,
 * costCrashing=57, tesseractBonus=ArcaneUpgBonus(54)*highestEndlessLevel, base cost=field[4],
 * costExponent=field[5] — all confirmed verbatim above, 0 mismatch on those.
 */
export function summUpgCost(baseCost, costExponent, level) {
  // Bare cost curve only (no bonus reductions applied — those are SummUpgBonus(49/57/72/75),
  // talent 595, ArcaneUpgBonus(54)*highestEndlessLevel, and RoG_BonusQTY(9)/(34), all listed above):
  return baseCost * Math.pow(costExponent, level);
}

