/** SumStoneTrialz(idx,0) — "SumStoneTrialz"==d, N.js byte 10716699 (m._customBlock_Thingies),
 * VERBATIM: `KRbest["SummzTrz"+idx]` if present, else 0. `idx` is the stone's colour index
 * (0-6 = white..cyan). This is the kills count — save key `KRbest` is a MAP keyed by string,
 * ALREADY documented in savemap/w45.mjs (CONFIRMED confidence) — read `s.get("KRbest")["SummzTrz"+idx]`.
 *
 * BOSS HP — "EnemyHP"==d, mode `GenINFO[146]==11` branch, N.js byte 10684810
 * (m._customBlock_Summoning2), VERBATIM:
 *   2 * SummonEnemies[14][SumStoneType(0,0)] * Math.pow(4000, SumStoneTrialz(SumStoneType(0,0), 0))
 * i.e. `2 * hpBase * 4000^kills` — CONFIRMED VERBATIM (not toolbox-only): matches
 * idleon-toolbox's `bossHp = 2 * enemy.hp * Math.pow(4000, killsNum)` exactly.
 *
 * BOSS DMG — "EnemyDMG"==d, same mode 11 branch, N.js byte 10682311 (m._customBlock_Summoning2),
 * VERBATIM: `.8 * SummonEnemies[13][SumStoneType(0,0)] * Math.pow(4000, SumStoneTrialz(...))`
 * i.e. `0.8 * dmgBase * 4000^kills` — NOT present anywhere in idleon-toolbox's summoning.ts (a
 * genuinely new finding from this pass, not a toolbox cross-check).
 *
 * ESSENCE MULTIPLIER — confirmed verbatim from a UI tooltip-draw routine near N.js byte 12176079
 * (unrelated actor behavior; drawing the stone's info panel), literal string concatenation:
 *   "" + Math.max(2, 1 + SumStoneTrialz(colourIdx, 0)) + "x_higher_bonuses"
 * i.e. `max(2, 1+kills)` — CONFIRMED VERBATIM, matches idleon-toolbox's
 * `Math.max(2, 1 + killsNum)` exactly. This multiplier is applied to ALL Summoning Upgrades of
 * that stone's essence colour (per the same tooltip's preceding line: "<Colour>_summoning_upgrades_give").
 *
 * SumStoneType(0,0) — "SumStoneType"==d, N.js byte 10716876 — reads the CURRENTLY-OPEN stone
 * battle's colour index off a live actor's animation frame; this is runtime UI/battle-selection
 * state, NOT save-derivable — a stat recipe consuming these formulas needs the colour index
 * supplied externally (e.g. "which stone is the user planning to fight"), same pattern as
 * ctx.activeVote in bonuses/summoning.mjs::votingBonus.
 */
export function summoningStoneBossHp(hpBase, kills) {
  return 2 * hpBase * Math.pow(4000, kills);
}
export function summoningStoneBossDmg(dmgBase, kills) {
  return 0.8 * dmgBase * Math.pow(4000, kills);
}
export function summoningStoneEssenceMultiplier(kills) {
  return Math.max(2, 1 + kills);
}

